/**
 * Per-module coverage threshold checker (PRD Section 13).
 *
 * Reads the Vitest JSON coverage report and validates that each module category
 * meets its required line coverage threshold. Run after `vitest run --coverage`.
 *
 * Usage:
 *   npx ts-node scripts/check-coverage.ts
 *
 * Expects coverage/coverage-final.json to exist (generated by vitest --coverage).
 */
import * as fs from 'fs';
import * as path from 'path';

interface ModuleThreshold {
  pattern: string;
  minLines: number;
  label: string;
}

const THRESHOLDS: ModuleThreshold[] = [
  { pattern: 'src/shared/billing-engine', label: 'Billing engine', minLines: 95 },
  { pattern: 'src/invoices/payment', label: 'Payment modules', minLines: 90 },
  { pattern: 'src/estimates/', label: 'Estimate calculations', minLines: 90 },
  { pattern: 'src/invoices/invoice', label: 'Invoice calculations', minLines: 90 },
  { pattern: 'src/proposals/execution/', label: 'Proposal execution', minLines: 85 },
  { pattern: 'src/auth/', label: 'Auth/RBAC', minLines: 85 },
  { pattern: 'src/middleware/', label: 'Middleware', minLines: 85 },
  { pattern: 'src/ai/', label: 'AI gateway', minLines: 80 },
  { pattern: 'src/customers/', label: 'Customers (CRUD)', minLines: 70 },
  { pattern: 'src/jobs/', label: 'Jobs (CRUD)', minLines: 70 },
  { pattern: 'src/locations/', label: 'Locations (CRUD)', minLines: 70 },
  { pattern: 'src/appointments/', label: 'Appointments (CRUD)', minLines: 70 },
  { pattern: 'src/notes/', label: 'Notes (CRUD)', minLines: 70 },
  { pattern: 'src/conversations/', label: 'Conversations (CRUD)', minLines: 70 },
];

interface FileCoverage {
  s: Record<string, number>;
  b: Record<string, number[]>;
}

function calculateLineCoverage(files: Record<string, FileCoverage>, pattern: string): number | null {
  const matchingFiles = Object.keys(files).filter((f) => f.includes(pattern));
  if (matchingFiles.length === 0) return null;

  let totalStatements = 0;
  let coveredStatements = 0;

  for (const file of matchingFiles) {
    const stmts = files[file].s;
    for (const count of Object.values(stmts)) {
      totalStatements++;
      if (count > 0) coveredStatements++;
    }
  }

  if (totalStatements === 0) return null;
  return (coveredStatements / totalStatements) * 100;
}

function main() {
  const coveragePath = path.resolve(__dirname, '..', 'coverage', 'coverage-final.json');

  if (!fs.existsSync(coveragePath)) {
    console.error('Coverage report not found. Run `npm run test:coverage` first.');
    console.error(`Expected at: ${coveragePath}`);
    process.exit(1);
  }

  const coverage = JSON.parse(fs.readFileSync(coveragePath, 'utf-8'));
  let failures = 0;

  console.log('Per-module coverage check (PRD Section 13)\n');
  console.log('Module'.padEnd(30) + 'Coverage'.padEnd(12) + 'Threshold'.padEnd(12) + 'Status');
  console.log('-'.repeat(66));

  for (const threshold of THRESHOLDS) {
    const lineCoverage = calculateLineCoverage(coverage, threshold.pattern);

    if (lineCoverage === null) {
      console.log(
        threshold.label.padEnd(30) +
        'N/A'.padEnd(12) +
        `${threshold.minLines}%`.padEnd(12) +
        'SKIP (no files)'
      );
      continue;
    }

    const passed = lineCoverage >= threshold.minLines;
    const status = passed ? 'PASS' : 'FAIL';

    if (!passed) failures++;

    console.log(
      threshold.label.padEnd(30) +
      `${lineCoverage.toFixed(1)}%`.padEnd(12) +
      `${threshold.minLines}%`.padEnd(12) +
      status
    );
  }

  console.log('-'.repeat(66));

  if (failures > 0) {
    console.error(`\n${failures} module(s) below coverage threshold.`);
    process.exit(1);
  } else {
    console.log('\nAll modules meet coverage thresholds.');
  }
}

main();
